const email = $input.item.json;

// Clean up email body — strip HTML tags and trim whitespace
const stripHtml = (str) => (str || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

return {
  json: {
    message_id: email.id,
    thread_id: email.threadId,
    subject: email.subject || '(no subject)',
    from_email: email.from?.email || email.from || '',
    from_name: email.from?.name || '',
    body_text: stripHtml(email.text || email.snippet || '').substring(0, 1500),
    date: email.date || new Date().toISOString(),
    labels: email.labelIds || []
  }
};

