const aiResult = JSON.parse($input.item.json.choices[0].message.content);
const email = $('Extract Email Fields').item.json;

// Map categories to Slack channels
const channelMap = {
  billing: 'YOUR_BILLING_CHANNEL_ID',
  bug: 'YOUR_BUGS_CHANNEL_ID',
  feature_request: 'YOUR_PRODUCT_CHANNEL_ID',
  question: 'YOUR_SUPPORT_CHANNEL_ID',
  complaint: 'YOUR_SUPPORT_CHANNEL_ID',
  other: 'YOUR_SUPPORT_CHANNEL_ID'
};

const priorityEmoji = {
  urgent: '🚨',
  high: '🔴',
  medium: '🟡',
  low: '🟢'
};

const sentimentEmoji = {
  positive: '😊',
  neutral: '😐',
  negative: '😠',
  very_negative: '😡'
};

return {
  json: {
    ...email,
    category: aiResult.category,
    priority: aiResult.priority,
    sentiment: aiResult.sentiment,
    summary: aiResult.summary,
    draft_reply: aiResult.draft_reply,
    internal_note: aiResult.internal_note,
    slack_channel: channelMap[aiResult.category] || channelMap.other,
    priority_emoji: priorityEmoji[aiResult.priority] || '⚪',
    sentiment_emoji: sentimentEmoji[aiResult.sentiment] || '😐'
  }
};

